// Shape a rich Discord embed from the Error Trigger payload.
const d = $input.first().json;
const wf = d.workflow || {};
const ex = d.execution || {};
const err = ex.error || {};

const payload = {
  username: 'n8n alerts',
  embeds: [
    {
      title: `🚨 Workflow failed — ${wf.name || 'unknown'}`,
      url: ex.url || undefined,
      color: 15158332, // red
      timestamp: new Date().toISOString(),
      fields: [
        { name: 'Failed node', value: '`' + (ex.lastNodeExecuted || 'n/a') + '`', inline: true },
        { name: 'Mode', value: ex.mode || 'n/a', inline: true },
        { name: 'Execution', value: ex.url ? `[open #${ex.id}](${ex.url})` : String(ex.id || 'n/a'), inline: true },
        { name: 'Error', value: '```' + String(err.message || 'no message').slice(0, 1000) + '```' },
      ],
      footer: { text: `n8n.phangan.ai • wf ${wf.id || ''}` },
    },
  ],
};
return [{ json: payload }];
